using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The MCP SDK discovers methods decorated with [McpServerTool] via source generation.
/// Constructor parameters (here HttpClient) are resolved from the DI container automatically.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    public WeatherTools(HttpClient http)
    {
        _http = http;
        _http.BaseAddress ??= new Uri("https://api.open-meteo.com");
    }

    [McpServerTool, Description("Get the current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        using var response = await _http.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        var current = json.GetProperty("current");

        return $"Temperature: {current.GetProperty("temperature_2m")}°C, "
             + $"Wind: {current.GetProperty("wind_speed_10m")} km/h";
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-16)")] int days = 7,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 16);

        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        using var response = await _http.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return json.GetProperty("daily").ToString();
    }
}

